-- Luke Chapter 8
-- Theme: The Word Sown, the Storm Stilled, and the Dead Raised — The Authority of Jesus over Every Domain
-- 56 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 8,
  'Luke 8 is a chapter of dramatic contrasts: the intimate company of devoted women who support Jesus''s ministry gives way to the vast crowds to whom the parabolic word is sown. The Parable of the Sower — the foundational parable (v.11: "this is the parable") — explains why the same gospel produces radically different results in different hearers. The four soils are four responses of the human heart to the word of God, and only the honest and good heart that hears and keeps the word bears fruit with patience.' ||
  'The lamp saying (vv.16-18) and the true family of Jesus (vv.19-21) reinforce the core principle: hearing and doing the word constitutes true spiritual kinship with Christ. Jesus''s natural family cannot reach him through the crowd; but those who hear and do God''s word are his mother and brothers. This reverses normal familial categories and establishes a new community defined entirely by response to the word.' ||
  'The second half of the chapter presents four mighty works that systematically extend Jesus''s authority over every threatening power. The stilling of the storm (vv.22-25) demonstrates authority over the natural world — a power attributed to YHWH alone in the Psalms (107:28-29). The exorcism of the Gadarene demoniac (vv.26-39) demonstrates authority over the supernatural world — a man living among tombs, naked, uncontrollable, is found clothed, in his right mind, sitting at Jesus''s feet. The healing of the woman with twelve years of bleeding (vv.43-48) and the raising of Jairus''s daughter (vv.41-42, 49-56) are interlaced — two cases of ritual impurity (a woman''s bleeding, a corpse) that Jesus overcomes without becoming defiled.' ||
  'The persistent thread through all four miracles is the question of faith. "Where is your faith?" (v.25). "Fear not: believe only" (v.50). "Thy faith hath made thee whole" (v.48). Faith is the open hand that receives what divine authority gives. Throughout chapter 8, Luke is building the Christological case that will culminate in Peter''s confession in chapter 9.',
  'The Word Sown, the Storm Stilled, and the Dead Raised — The Authority of Jesus over Every Domain',
  'σπόρος (sporos)',
  'sporos means seed or sowing. In the Parable of the Sower, Jesus uses the agricultural image of the seed to describe the word of God (v.11: "The seed is the word of God"). The fate of the seed depends on the soil, not the sower. This agricultural metaphor frames the entire chapter''s theme: the sovereign word of Jesus is sown into every domain of human existence — hearts, storms, demons, disease, and death — and in each case his authority prevails.',
  '["Women Who Followed and Supported the Ministry (vv.1-3)","The Parable of the Sower and Its Interpretation (vv.4-15)","The Lamp, the Ear, and the True Family of Jesus (vv.16-21)","Authority over Nature: The Storm Stilled (vv.22-25)","Authority over Demons: The Gadarene Demoniac Healed (vv.26-39)","Authority over Disease and Death: Jairus''s Daughter and the Bleeding Woman (vv.40-56)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And it came to pass afterward, that he went throughout every city and village, preaching and shewing the glad tidings of the kingdom of God: and the twelve were with him,', 'Καὶ ἐγένετο ἐν τῷ καθεξῆς καὶ αὐτὸς διώδευεν κατὰ πόλιν καὶ κώμην κηρύσσων καὶ εὐαγγελιζόμενος τὴν βασιλείαν τοῦ Θεοῦ· καὶ οἱ δώδεκα σὺν αὐτῷ,', 'Kai egeneto en tō kathexēs kai autos diōdeuen kata polin kai kōmēn kērussōn kai euangelizomenos tēn basileian tou Theou; kai hoi dōdeka sun autō,', '"Throughout every city and village" — a systematic itinerant campaign. Luke uses two verbs for the proclamation: kērussōn (heralding, public announcement) and euangelizomenos (bringing glad tidings). The double verb captures both the authority of proclamation and the joy of its content. The Twelve are present as apprentices in ministry.', NULL),
  (2, 'And certain women, which had been healed of evil spirits and infirmities, Mary called Magdalene, out of whom went seven devils,', 'καὶ γυναῖκές τινες αἳ ἦσαν τεθεραπευμέναι ἀπὸ πνευμάτων πονηρῶν καὶ ἀσθενειῶν, Μαρία ἡ καλουμένη Μαγδαληνή, ἀφ'' ἧς δαιμόνια ἑπτὰ ἐξεληλύθει,', 'kai gunaikes tines hai ēsan tetherapeumenai apo pneumatōn ponērōn kai astheneiōn, Maria hē kaloumenē Magdalēnē, aph'' hēs daimonia hepta exelēluthei,', 'Luke uniquely records the women who traveled with Jesus. Mary Magdalene is identified first and most prominently. "Seven demons" indicates severe spiritual oppression — seven being the number of completeness, suggesting total demonic domination now completely overthrown. She will be present at the crucifixion, burial, and resurrection (23:49,55; 24:1-10). Her devotion was commensurate with her deliverance.', NULL),
  (3, 'And Joanna the wife of Chuza Herod''s steward, and Susanna, and many others, which ministered unto him of their substance.', 'καὶ Ἰωάννα γυνὴ Χουζᾶ ἐπιτρόπου Ἡρῴδου, καὶ Σουσάννα, καὶ ἕτεραι πολλαί, αἵτινες διηκόνουν αὐτοῖς ἐκ τῶν ὑπαρχόντων αὐταῖς.', 'kai Iōanna gunē Chouza epitropou Hērōdou, kai Sousanna, kai heterai pollai, haitines diēkonoun autois ek tōn huparchontōn autais.', 'Joanna''s connection to Herod''s court (Chuza was steward/estate manager) represents the penetration of the gospel into the highest social circles. These women "ministered unto him of their substance" — they financed the ministry from their own resources. This is an extraordinary detail: women were the economic patrons of the traveling band. Luke''s inclusion honors their vital and often overlooked role.', NULL),
  (4, 'And when much people were gathered together, and were come to him out of every city, he spake by a parable:', 'Συνιόντος δὲ ὄχλου πολλοῦ καὶ τῶν κατὰ πόλιν ἐπιπορευομένων πρὸς αὐτόν, εἶπεν διὰ παραβολῆς,', 'Suniontos de ochlou pollou kai tōn kata polin epiporeuomenōn pros auton, eipen dia parabolēs,', 'The size of the crowd — gathering from every city — is the backdrop against which the parable is heard. The large crowd contains all four types of "soil." Jesus speaks "by a parable" (dia parabolēs — through, by means of). The parable form simultaneously reveals and conceals: it illuminates the receptive and hides truth from the indifferent (vv.10).', NULL),
  (5, 'A sower went out to sow his seed: and as he sowed, some fell by the way side; and it was trodden down, and the fowls of the air devoured it.', 'Ἐξῆλθεν ὁ σπείρων τοῦ σπεῖραι τὸν σπόρον αὐτοῦ· καὶ ἐν τῷ σπείρειν αὐτόν, ὃ μὲν ἔπεσεν παρὰ τὴν ὁδόν, καὶ κατεπατήθη, καὶ τὰ πετεινὰ τοῦ οὐρανοῦ κατέφαγεν αὐτό.', 'Exēlthen ho speirōn tou speirai ton sporon autou; kai en tō speirein auton, ho men epesen para tēn hodon, kai katepathē, kai ta peteina tou ouranou katephagen auto.', 'Ancient sowing practice broadcast seed widely, with seeds inevitably landing in different conditions. "By the way side" (para tēn hodon) — the hardened path where seed cannot penetrate. The birds immediately devour what lies exposed. Jesus will interpret the birds as the devil (v.12). The path represents a heart impervious to the word — hardened by pride, preoccupation, or deliberate closure.', NULL),
  (6, 'And some fell upon a rock; and as soon as it was sprung up, it withered away, because it lacked moisture.', 'καὶ ἕτερον κατέπεσεν ἐπὶ τὴν πέτραν, καὶ φυὲν ἐξηράνθη διὰ τὸ μὴ ἔχειν ἰκμάδα.', 'kai heteron katepesen epi tēn petran, kai phuen exēranthe dia to mē echein ikmada.', '"Upon a rock" — a thin layer of soil over bedrock, common in Palestinian terrain. Seeds germinate quickly in such soil due to warmth, but roots cannot penetrate and the plant has no moisture reserve. The quick initial growth followed by withering describes shallow emotional response: faith that springs up in enthusiasm but has no root in the deep soil of genuine conviction and ongoing discipleship.', NULL),
  (7, 'And some fell among thorns; and the thorns sprang up with it, and choked it.', 'καὶ ἕτερον ἔπεσεν ἐν μέσῳ τῶν ἀκανθῶν, καὶ συμφυεῖσαι αἱ ἄκανθαι ἀπέπνιξαν αὐτό.', 'kai heteron epesen en mesō tōn akanthōn, kai sumphuisai hai akanthai apepnixan auto.', '"Choked" (apepnixan — throttled, suffocated). The thorns grow simultaneously with the seed, but their root system is deeper and their growth more vigorous. The word germinates but is progressively starved of light and nutrients. Jesus will identify the thorns as "cares and riches and pleasures of this life" (v.14) — competing loyalties that gradually displace the word''s priority.', NULL),
  (8, 'And other fell on good ground, and sprang up, and bare fruit an hundredfold. And when he had said these things, he cried, He that hath ears to hear, let him hear.', 'καὶ ἕτερον ἔπεσεν εἰς τὴν γῆν τὴν ἀγαθήν, καὶ φυὲν ἐποίησεν καρπὸν ἑκατονταπλασίονα. ταῦτα λέγων ἐφώνει, Ὁ ἔχων ὦτα ἀκούειν ἀκουέτω.', 'kai heteron epesen eis tēn gēn tēn agathēn, kai phuen epoiēsen karpon hekatontaplasiōna. tauta legōn ephōnei, Ho echōn ōta akouein akouetō.', '"An hundredfold" — extraordinary fruitfulness by any agricultural standard (a typical harvest was 5-10 fold). The good soil does not merely survive; it multiplies extravagantly. "He that hath ears to hear, let him hear" — a repeated call to active listening throughout the Gospels. The phrase acknowledges that hearing is not automatic; it requires spiritual receptivity and intentional openness.', NULL),
  (9, 'And his disciples asked him, saying, What might this parable be?', 'Ἐπηρώτων δὲ αὐτὸν οἱ μαθηταὶ αὐτοῦ λέγοντες, Τίς εἴη ἡ παραβολὴ αὕτη;', 'Epērōtōn de auton hoi mathētai autou legontes, Tis eiē hē parabolē hautē?', 'The disciples'' question ("what might this parable be?") is itself evidence of the distinction Jesus draws in verse 10: they ask, they seek, they knock. Their inquiry is not passive puzzlement but active desire for understanding. This is the mark of the good-soil heart: it does not let the word lie on the surface but pursues deeper comprehension.', NULL),
  (10, 'And he said, Unto you it is given to know the mysteries of the kingdom of God: but to others in parables; that seeing they might not see, and hearing they might not understand.', 'ὁ δὲ εἶπεν, Ὑμῖν δέδοται γνῶναι τὰ μυστήρια τῆς βασιλείας τοῦ Θεοῦ· τοῖς δὲ λοιποῖς ἐν παραβολαῖς, ἵνα βλέποντες μὴ βλέπωσιν καὶ ἀκούοντες μὴ συνιῶσιν.', 'ho de eipen, Humin dedotai gnōnai ta mustēria tēs basileias tou Theou; tois de loipois en parabolais, hina blepontes mē blepōsin kai akouontes mē suniōsin.', '"Mysteries" (mustēria — hidden realities now disclosed). The kingdom''s mysteries are not intellectually inaccessible secrets but realities that require spiritual regeneration to perceive. The citation of Isaiah 6:9 (judicial hardening) describes a tragic divine irony: those who persistently refuse to see are given parables that simultaneously offer the truth and withhold it from those who have closed their eyes to it.', NULL),
  (11, 'Now the parable is this: The seed is the word of God.', 'Ἔστιν δὲ αὕτη ἡ παραβολή· ὁ σπόρος ἐστὶν ὁ λόγος τοῦ Θεοῦ.', 'Estin de hautē hē parabolē; ho sporos estin ho logos tou Theou.', '"This is the parable" — a marker of supreme importance. The Parable of the Sower is the parable, the key that unlocks all other parables (cf. Mark 4:13). The seed is identified as "the word of God" (logos tou Theou) — not a word about God, not a human religious concept, but the living, powerful word that God himself speaks. All subsequent parable interpretation proceeds from this foundation.', NULL),
  (12, 'Those by the way side are they that hear; then cometh the devil, and taketh away the word out of their hearts, lest they should believe and be saved.', 'οἱ δὲ παρὰ τὴν ὁδόν εἰσιν οἱ ἀκούσαντες, εἶτα ἔρχεται ὁ διάβολος καὶ αἴρει τὸν λόγον ἀπὸ τῆς καρδίας αὐτῶν, ἵνα μὴ πιστεύσαντες σωθῶσιν.', 'hoi de para tēn hodon eisin hoi akousantes, eita erchetai ho diabolos kai airei ton logon apo tēs kardias autōn, hina mē pisteusantes sōthōsin.', 'The devil''s purpose is explicitly stated: "lest they should believe and be saved." This reveals the cosmic stakes of gospel proclamation. The adversary''s strategy is not to dispute the word but to remove it before it can take root — through distraction, interruption, indifference. The hardened heart is not merely neutral; it is contested ground.', NULL),
  (13, 'They on the rock are they, which, when they hear, receive the word with joy; and these have no root, which for a while believe, and in time of temptation fall away.', 'οἱ δὲ ἐπὶ τῆς πέτρας οἳ ὅταν ἀκούσωσιν μετὰ χαρᾶς δέχονται τὸν λόγον, καὶ οὗτοι ῥίζαν οὐκ ἔχουσιν, οἳ πρὸς καιρὸν πιστεύουσιν καὶ ἐν καιρῷ πειρασμοῦ ἀφίστανται.', 'hoi de epi tēs petras hoi hotan akousōsin meta charas dechontai ton logon, kai houtoi rhizan ouk echousin, hoi pros kairon pisteuousin kai en kairō peirasmou aphistantai.', '"Receive with joy" — emotional enthusiasm is not the same as genuine faith. "For a while believe" — temporary faith is not saving faith. "In time of temptation fall away" (aphistantai — apostatize, stand away from). The rocky-soil person demonstrates an enthusiasm conditioned by favorable circumstances; when the cost becomes real, the attraction evaporates. True faith is tested and proven, not merely felt.', NULL),
  (14, 'And that which fell among thorns are they, which, when they have heard, go forth, and are choked with cares and riches and pleasures of this life, and bring no fruit to perfection.', 'τὸ δὲ εἰς τὰς ἀκάνθας πεσόν, οὗτοί εἰσιν οἱ ἀκούσαντες, καὶ ὑπὸ μεριμνῶν καὶ πλούτου καὶ ἡδονῶν τοῦ βίου πορευόμενοι συμπνίγονται καὶ οὐ τελεσφοροῦσιν.', 'to de eis tas akanthas peson, houtoi eisin hoi akousantes, kai hupo merimnōn kai ploutou kai hēdonōn tou biou poreuomenoi sumpnigontai kai ou telesporousin.', '"Cares" (merimnōn — anxious worry), "riches" (ploutou), and "pleasures" (hēdonōn — from which we get "hedonism"). These are not neutral life circumstances but active competing commitments that "choke" (sumpnigontai — throttle completely) the word. "Bring no fruit to perfection" (ou telesporousin — fail to ripen to full fruiting) — the plant exists but never matures. A fruitless Christian life is the result of divided loyalty.', NULL),
  (15, 'But that on the good ground are they, which in an honest and good heart, having heard the word, keep it, and bring forth fruit with patience.', 'τὸ δὲ ἐν τῇ καλῇ γῇ, οὗτοί εἰσιν οἵτινες ἐν καρδίᾳ καλῇ καὶ ἀγαθῇ ἀκούσαντες τὸν λόγον κατέχουσιν καὶ καρποφοροῦσιν ἐν ὑπομονῇ.', 'to de en tē kalē gē, houtoi eisin hoitines en kardia kalē kai agathē akousantes ton logon katechousin kai karpophorousin en hupomonē.', '"An honest and good heart" (kardia kalē kai agathē — a beautiful and good heart). The two adjectives (kalos = beautiful/noble; agathos = good/morally sound) describe a heart that is both receptive in quality and sound in moral condition — a heart prepared by the Spirit. "Keep it" (katechousin — hold fast, retain). "With patience" (hupomonē — steadfast endurance, not impatience). Fruitfulness is not immediate but develops through patient perseverance.', NULL),
  (16, 'No man, when he hath lighted a candle, covereth it with a vessel, or putteth it under a bed; but setteth it on a candlestick, that they which enter in may see the light.', 'Οὐδεὶς δὲ λύχνον ἅψας καλύπτει αὐτὸν σκεύει ἢ ὑποκάτω κλίνης τίθησιν, ἀλλ'' ἐπὶ λυχνίας τίθησιν, ἵνα οἱ εἰσπορευόμενοι βλέπωσιν τὸ φῶς.', 'Oudeis de luchnon hapsas kaluptei auton skeuei ē hupokatō klinēs tithēsin, all'' epi luchnias tithēsin, hina hoi eisporeuomenoi blepōsin to phōs.', 'The lamp saying follows the parable immediately to warn against the temptation of inward, private faith. Light is inherently meant to reveal. The disciples who have received the mysteries of the kingdom are not to hoard them but to display them. The word received in the good heart is not a private treasure but a public witness — the light that illuminates others.', NULL),
  (17, 'For nothing is secret, that shall not be made manifest; neither any thing hid, that shall not be known and come abroad.', 'οὐ γάρ ἐστιν κρυπτὸν ὃ οὐ φανερὸν γενήσεται, οὐδὲ ἀπόκρυφον ὃ οὐ μὴ γνωσθῇ καὶ εἰς φανερὸν ἔλθῃ.', 'ou gar estin krupton ho ou phaneron genēsetai, oude apokruphon ho ou mē gnōsthē kai eis phaneron elthē.', 'A universal principle with two applications: (1) the hidden truth of the kingdom will eventually be fully revealed (eschatologically); (2) the character of each hearer — which type of soil — will eventually be disclosed by the fruit (or lack thereof) of their life. There is no permanent concealment in God''s economy; all will be made manifest at the judgment.', NULL),
  (18, 'Take heed therefore how ye hear: for whosoever hath, to him shall be given; and whosoever hath not, from him shall be taken even that which he seemeth to have.', 'βλέπετε οὖν πῶς ἀκούετε· ὃς γὰρ ἂν ἔχῃ, δοθήσεται αὐτῷ· καὶ ὃς ἂν μὴ ἔχῃ, καὶ ὃ δοκεῖ ἔχειν ἀρθήσεται ἀπ'' αὐτοῦ.', 'blepete oun pōs akouete; hos gar an echē, dothēsetai autō; kai hos an mē echē, kai ho dokei echein arthēsetai ap'' autou.', '"Take heed how ye hear" — not merely what you hear but how. The quality of hearing determines spiritual growth or atrophy. "Whosoever hath" — the one who has genuinely received, believed, and acted on the word will receive more insight and grace. "Whosoever hath not" — the one who merely appears to have, who has a formal religion without true reception, will lose even that appearance. Spiritual growth is not static; it either advances or retreats.', NULL),
  (19, 'Then came to him his mother and his brethren, and could not come at him for the press.', 'Παρεγένετο δὲ πρὸς αὐτὸν ἡ μήτηρ καὶ οἱ ἀδελφοὶ αὐτοῦ, καὶ οὐκ ἠδύναντο συντυχεῖν αὐτῷ διὰ τὸν ὄχλον.', 'Paregeneto de pros auton hē mētēr kai hoi adelphoi autou, kai ouk ēdunanto suntuchein autō dia ton ochlon.', 'The arrival of Jesus''s natural family creates a structural contrast with the previous teaching. Physical kinship — even with the mother of Jesus — cannot guarantee access to the kingdom. The "brethren" (adelphoi) were the sons of Mary and Joseph born after Jesus (Matt 1:25). Their inability to reach Jesus through the crowd provides the occasion for the most radical redefinition of family in the NT.', NULL),
  (20, 'And it was told him by certain which said, Thy mother and thy brethren stand without, desiring to see thee.', 'ἀπηγγέλη δὲ αὐτῷ λέγοντων, Ἡ μήτηρ σου καὶ οἱ ἀδελφοί σου ἑστήκασιν ἔξω ἰδεῖν σε θέλοντες.', 'apēngelē de autō legontōn, Hē mētēr sou kai hoi adelphoi sou hestēkasin exō idein se thelontes.', '"Without" (exō — outside) contrasts with "within" (the disciples gathered around Jesus, v.21). The physical geography becomes a spiritual metaphor. Those who are inside are those who hear and do the word; those who remain outside — even family members — do so by their own choice not to press into the teaching.', NULL),
  (21, 'And he answered and said unto them, My mother and my brethren are these which hear the word of God, and do it.', 'ὁ δὲ ἀποκριθεὶς εἶπεν πρὸς αὐτούς, Μήτηρ μου καὶ ἀδελφοί μου οὗτοί εἰσιν οἱ τὸν λόγον τοῦ Θεοῦ ἀκούοντες καὶ ποιοῦντες αὐτόν.', 'ho de apokritheis eipen pros autous, Mētēr mou kai adelphoi mou houtoi eisin hoi ton logon tou Theou akouontes kai poiountes auton.', '"Hear the word of God, and do it" (akouontes kai poiountes) — precisely the definition of the good-soil hearer (v.15), now applied to the definition of spiritual family. This is not a rejection of Mary but a proclamation of the highest privilege available to any human: to be in the intimate family of Jesus through obedient hearing. Mary herself was the supreme example of this (1:38: "be it unto me according to thy word").', NULL),
  (22, 'Now it came to pass on a certain day, that he went into a ship with his disciples: and he said unto them, Let us go over unto the other side of the lake. And they launched forth.', 'Ἐγένετο δὲ ἐν μιᾷ τῶν ἡμερῶν καὶ αὐτὸς ἐνέβη εἰς πλοῖον καὶ οἱ μαθηταὶ αὐτοῦ, καὶ εἶπεν πρὸς αὐτούς, Διέλθωμεν εἰς τὸ πέραν τῆς λίμνης· καὶ ἀνήχθησαν.', 'Egeneto de en mia tōn hēmerōn kai autos enebē eis ploion kai hoi mathētai autou, kai eipen pros autous, Dielthōmen eis to peran tēs limnēs; kai anēchthēsan.', 'The Sea of Galilee (here called limne — lake) was 13 miles long and 7 miles wide, surrounded by hills that created sudden, violent storms. "The other side" was the Gentile Decapolis region (Gerasa, v.26). The crossing is purposeful — Jesus is extending his ministry across the ethnic boundary. The storm that arises is not incidental; it is the opposition to that crossing.', NULL),
  (23, 'But as they sailed he fell asleep: and there came down a storm of wind on the lake; and they were filled with water, and were in jeopardy.', 'πλεόντων δὲ αὐτῶν ἀφύπνωσεν· καὶ κατέβη λαῖλαψ ἀνέμου εἰς τὴν λίμνην, καὶ συνεπληροῦντο καὶ ἐκινδύνευον.', 'pleontōn de autōn aphupnōsen; kai katebē lailaps anemou eis tēn limnēn, kai suneplērounto kai ekinduneuon.', '"He fell asleep" (aphupnōsen) — a vivid detail of Jesus''s genuine humanity. He was tired from ministry. "A storm of wind" (lailaps anemou — a whirlwind, squall) — a meteorological term for a sudden violent storm. "Were in jeopardy" (ekinduneuon — were in danger, at risk of their lives). Professional fishermen who knew this lake were terrified, indicating the severity of the storm.', NULL),
  (24, 'And they came to him, and awoke him, saying, Master, master, we perish. Then he arose, and rebuked the wind and the raging of the water: and they ceased, and there was a calm.', 'προσελθόντες δὲ διήγειραν αὐτὸν λέγοντες, Ἐπιστάτα ἐπιστάτα, ἀπολλύμεθα. ὁ δὲ διεγερθεὶς ἐπετίμησεν τῷ ἀνέμῳ καὶ τῷ κλύδωνι τοῦ ὕδατος· καὶ ἐπαύσαντο, καὶ ἐγένετο γαλήνη.', 'proselthontes de diēgeiran auton legontes, Epistata epistata, apollumetha. ho de diegerthe epetimēsen tō anemō kai tō klydōni tou hudatos; kai epausanto, kai egeneto galēnē.', '"Master, Master" (Epistata — commander, overseer — Luke''s distinctive title, used 6 times only by him). "We perish!" — present tense: we are perishing. Jesus "rebuked" (epetimēsen) the wind — the same verb used for rebuking demons (4:35,39; 9:42). The storm is treated as a hostile power to be silenced, not merely a natural phenomenon to be weathered. The immediate calm (galēnē — dead calm) was itself miraculous.', NULL),
  (25, 'And he said unto them, Where is your faith? And they being afraid wondered, saying one to another, What manner of man is this! for he commandeth even the winds and water, and they obey him.', 'εἶπεν δὲ αὐτοῖς, Ποῦ ἐστιν ἡ πίστις ὑμῶν; φοβηθέντες δὲ ἐθαύμασαν, λέγοντες πρὸς ἀλλήλους, Τίς ἄρα οὗτός ἐστιν, ὅτι καὶ τοῖς ἀνέμοις ἐπιτάσσει καὶ τῷ ὕδατι, καὶ ὑπακούουσιν αὐτῷ;', 'eipen de autois, Pou estin hē pistis humōn? phobēthenthes de ethaumasan, legontes pros allēlous, Tis ara houtos estin, hoti kai tois anemois epitassei kai tō hudati, kai hupakouousin autō?', '"Where is your faith?" — not "you have no faith" but a probing question implying they had received enough evidence to trust. The disciples'' fear of the storm was replaced by a greater awe ("feared exceedingly" — phobēthentes) before the one who stilled it. "What manner of man is this?" (Tis ara houtos estin?) — the question that drives the entire chapter and is answered explicitly in Peter''s confession (9:20). The combination of commanding wind and water was recognized as divine prerogative (Ps 107:28-29; Job 38:8-11).', NULL),
  (26, 'And they arrived at the country of the Gadarenes, which is over against Galilee.', 'Καὶ κατέπλευσαν εἰς τὴν χώραν τῶν Γαδαρηνῶν, ἥτις ἐστὶν ἀντιπέρα τῆς Γαλιλαίας.', 'Kai katepleusan eis tēn chōran tōn Gadarēnōn, hētis estin antipera tēs Galilaias.', 'The Gadarene region (also called Gerasene/Gergesene in textual variants) was Gentile territory east of the Sea of Galilee, part of the Decapolis. "Over against Galilee" emphasizes the cultural crossing. The pigs (v.33) confirm the Gentile context, as Jews did not keep swine. Jesus deliberately crosses cultural and ethnic boundaries to bring liberation.', NULL),
  (27, 'And when he went forth to land, there met him out of the city a certain man, which had devils long time, and ware no clothes, neither abode in any house, but in the tombs.', 'ἐξελθόντι δὲ αὐτῷ ἐπὶ τὴν γῆν ὑπήντησεν ἀνήρ τις ἐκ τῆς πόλεως ὃς εἶχεν δαιμόνια ἐκ χρόνων ἱκανῶν, καὶ ἱμάτιον οὐκ ἐνεδιδύσκετο καὶ ἐν οἰκίᾳ οὐκ ἔμενεν ἀλλ'' ἐν τοῖς μνήμασιν.', 'exelthonti de autō epi tēn gēn hupēntēsen anēr tis ek tēs poleōs hos eichen daimonia ek chronōn hikanōn, kai himation ouk eneDidusketo kai en oikia ouk emenen all'' en tois mnēmasin.', 'A man stripped of every mark of humanity: no clothes, no home, living among the dead. The tombs symbolized the utmost degree of defilement and the realm of death. "Long time" (ek chronōn hikanōn) — a chronic, entrenched condition. The meeting of Jesus with this man the moment he steps ashore is deliberate: Jesus came specifically for the most desperate case in the region.', NULL),
  (28, 'When he saw Jesus, he cried out, and fell down before him, and with a loud voice said, What have I to do with thee, Jesus, thou Son of God most high? I beseech thee, torment me not.', 'ἰδὼν δὲ τὸν Ἰησοῦν ἀνακράξας προσέπεσεν αὐτῷ καὶ φωνῇ μεγάλῃ εἶπεν, Τί ἐμοὶ καὶ σοί, Ἰησοῦ υἱὲ τοῦ Θεοῦ τοῦ ὑψίστου; δέομαί σου, μή με βασανίσῃς.', 'idōn de ton Iēsoun anakraxas prosepesen autō kai phōnē megalē eipen, Ti emoi kai soi, Iēsou huie tou Theou tou Hupsistou? deomai sou, mē me basanisēs.', '"Son of God most high" (huie tou Theou tou Hupsistou) — the demons'' knowledge of Jesus''s divine identity surpasses that of the disciples. The demons fear and acknowledge; the disciples wonder and ask. "Torment me not" (mē me basanisēs) — anticipates judgment. The word basanizō is used in Revelation for eschatological torment. The demon recognizes that Jesus has authority to consign it to its final punishment.', NULL),
  (29, 'For he had commanded the unclean spirit to come out of the man. For oftentimes it had caught him: and he was kept bound with chains and in fetters; and he brake the bands, and was driven of the devil into the wilderness.', 'παρήγγελλεν γὰρ τῷ πνεύματι τῷ ἀκαθάρτῳ ἐξελθεῖν ἀπὸ τοῦ ἀνθρώπου. πολλοῖς γὰρ χρόνοις συνηρπάκει αὐτόν, καὶ ἐδεσμεῖτο ἀλύσεσιν καὶ πέδαις φυλασσόμενος, καὶ διαρρήσσων τὰ δεσμὰ ἠλαύνετο ἀπὸ τοῦ δαιμονίου εἰς τὰς ἐρήμους.', 'parēngellen gar tō pneumati tō akathartō exelthein apo tou anthrōpou. pollois gar chronois sunērpakei auton, kai edesmeito alusesi kai pedais phulassomenos, kai diarrhēssōn ta desma ēlauneto apo tou daimoniou eis tas erēmous.', 'The imperfect tense "had commanded" indicates Jesus gave the command before the demon spoke. The demon''s speech was a response to the already-issued command. The description of chains broken, fetters burst apart reveals a strength beyond human containment. The community''s repeated attempts at physical restraint had all failed; only the word of Jesus succeeds where all human effort has been exhausted.', NULL),
  (30, 'And Jesus asked him, saying, What is thy name? And he said, Legion: because many devils were entered into him.', 'ἐπηρώτησεν δὲ αὐτὸν ὁ Ἰησοῦς λέγων, Τί σοί ἐστιν ὄνομα; ὁ δὲ εἶπεν, Λεγιών· ὅτι εἰσῆλθεν δαιμόνια πολλὰ εἰς αὐτόν.', 'epērōtēsen de auton ho Iēsous legōn, Ti soi estin onoma? ho de eipen, Legiōn; hoti eisēlthen daimonia polla eis auton.', '"Legion" — a Roman military legion comprised 6,000 soldiers. The name communicates both the multitude of demons and the military imagery of organized occupation. The use of a Roman military term in a Gentile territory may carry political overtones: even Rome''s most feared military force cannot compete with the one who commands wind and sea. Jesus asks for the name — knowing it — but the dialogue demonstrates his total control of the situation.', NULL),
  (31, 'And they besought him that he would not command them to go out into the deep.', 'καὶ παρεκάλουν αὐτὸν ἵνα μὴ ἐπιτάξῃ αὐτοῖς εἰς τὴν ἄβυσσον ἀπελθεῖν.', 'kai parekaloun auton hina mē epitaxē autois eis tēn abusson apelthein.', '"The deep" (abusson — abyss) is the place of final imprisonment for demonic powers (Rev 9:1-2; 20:1-3; cf. 2 Pet 2:4; Jude 6). The demons'' request reveals their knowledge of eschatological judgment and their fear of premature consignment to it. They prefer even the pigs to the abyss. This detail confirms that the demonic world operates under divine authority and within divinely set limits.', NULL),
  (32, 'And there was there an herd of many swine feeding on the mountain: and they besought him that he would suffer them to enter into them. And he suffered them.', 'ἦν δὲ ἐκεῖ ἀγέλη χοίρων ἱκανῶν βοσκομένη ἐν τῷ ὄρει· καὶ παρεκάλεσαν αὐτὸν ἵνα ἐπιτρέψῃ αὐτοῖς εἰς ἐκείνους εἰσελθεῖν· καὶ ἐπέτρεψεν αὐτοῖς.', 'ēn de ekei agelē choirōn hikanōn boskomenē en tō orei; kai parekaleson auton hina epitrepsē autois eis ekeinous eiselthein; kai epetrepsen autois.', '"He suffered them" — Jesus grants the request, but within his own sovereign permission. He does not lose control of the situation. The swine herd''s subsequent self-destruction in the lake demonstrates the true nature of demonic influence: it brings only death and destruction to whatever it inhabits. The demons'' entry into the pigs and their immediate death reveals what they had been doing to the man.', NULL),
  (33, 'Then went the devils out of the man, and entered into the swine: and the herd ran violently down a steep place into the lake, and were choked.', 'ἐξελθόντα δὲ τὰ δαιμόνια ἀπὸ τοῦ ἀνθρώπου εἰσῆλθεν εἰς τοὺς χοίρους· καὶ ὥρμησεν ἡ ἀγέλη κατὰ τοῦ κρημνοῦ εἰς τὴν λίμνην καὶ ἀπεπνίγη.', 'exelthonta de ta daimonia apo tou anthrōpou eisēlthen eis tous choirous; kai hōrmēsen hē agelē kata tou krēmnou eis tēn limnēn kai apepnigē.', '"Ran violently" (hōrmēsen — rushed headlong, an explosive movement). The pigs'' suicidal charge into the lake mirrors the destruction the same demonic power had sought to bring to the man. The contrast between the man — now clothed and in his right mind (v.35) — and the drowned pigs is stark. Human restoration is worth more than an entire herd. The economic loss is real, but the man''s value surpasses it.', NULL),
  (34, 'When they that fed them saw what was done, they fled, and went and told it in the city and in the country.', 'ἰδόντες δὲ οἱ βόσκοντες τὸ γεγονὸς ἔφυγον καὶ ἀπήγγειλαν εἰς τὴν πόλιν καὶ εἰς τοὺς ἀγρούς.', 'idontes de hoi boskontes to gegonos ephugon kai apēngeilan eis tēn polin kai eis tous agrous.', 'The herdsmen flee in fear — a typical response to a divine manifestation (theophanic fear). They become unintentional evangelists, spreading the news throughout the city and countryside. Their report draws a crowd of investigators, who are themselves divided in their response (v.37).', NULL),
  (35, 'Then they went out to see what was done; and came to Jesus, and found the man, out of whom the devils were departed, sitting at the feet of Jesus, clothed, and in his right mind: and they were afraid.', 'ἐξῆλθον δὲ ἰδεῖν τὸ γεγονὸς, καὶ ἦλθον πρὸς τὸν Ἰησοῦν, καὶ εὗρον καθήμενον τὸν ἄνθρωπον ἀφ'' οὗ τὰ δαιμόνια ἐξεληλύθει ἱματισμένον καὶ σωφρονοῦντα παρὰ τοὺς πόδας τοῦ Ἰησοῦ, καὶ ἐφοβήθησαν.', 'exēlthon de idein to gegonos, kai ēlthon pros ton Iēsoun, kai heuron kathēmenon ton anthrōpon aph'' hou ta daimonia exelēluthei himatismenon kai sōphronounta para tous podas tou Iēsou, kai ephobēthēsan.', '"Sitting at the feet of Jesus, clothed, and in his right mind" (sōphronounta — sound-minded, self-controlled). Three restoration markers: posture (seated, at rest), clothing (restored to social norms), and mind (rational, integrated). Sitting "at the feet of Jesus" is the posture of a disciple (Mary in 10:39; Acts 22:3 — Paul at Gamaliel''s feet). The man has gone from the tombs to the Teacher''s feet. This is the fullest picture of salvation in Luke 8.', NULL),
  (36, 'They also which saw it told them by what means he that was possessed of the devils was healed.', 'ἀπήγγειλαν δὲ αὐτοῖς οἱ ἰδόντες πῶς ἐσώθη ὁ δαιμονισθείς.', 'apēngeilan de autois hoi idontes pōs esōthē ho daimonistheis.', '"Was healed" (esōthē — was saved/healed, the same word). Luke uses the comprehensive salvation word for the exorcism, confirming that deliverance from demonic power is included in the saving work of Jesus. The eyewitness account they heard should have produced faith; instead it produces a request that Jesus leave (v.37).', NULL),
  (37, 'Then the whole multitude of the country of the Gadarenes round about besought him to depart from them; for they were taken with great fear: and he went up into the ship, and returned back again.', 'καὶ ἠρώτησεν αὐτὸν ἅπαν τὸ πλῆθος τῆς περιχώρου τῶν Γαδαρηνῶν ἀπελθεῖν ἀπ'' αὐτῶν, ὅτι φόβῳ μεγάλῳ συνείχοντο· αὐτὸς δὲ ἐμβὰς εἰς πλοῖον ὑπέστρεψεν.', 'kai ērōtēsen auton hapan to plēthos tēs perichōrou tōn Gadarēnōn apelthein ap'' autōn, hoti phobō megalō suneichonto; autos de embas eis ploion hupestrepsen.', 'The community''s rejection is economically driven (the pigs represented significant wealth) but expressed as fear. They ask Jesus to leave. He honors the request — he never forces his presence on those who reject it. The tragedy is that they received a demonstration of the most extraordinary power and chose loss over transformation. Fear of the cost of following Jesus kept them from the gain.', NULL),
  (38, 'Now the man out of whom the devils were departed besought him that he might be with him: but Jesus sent him away, saying,', 'ἐδεῖτο δὲ αὐτοῦ ὁ ἀνὴρ ἀφ'' οὗ ἐξεληλύθει τὰ δαιμόνια εἶναι σὺν αὐτῷ· ἀπέλυσεν δὲ αὐτὸν ὁ Ἰησοῦς λέγων,', 'edeito de autou ho anēr aph'' hou exelēluthei ta daimonia einai sun autō; apelusen de auton ho Iēsous legōn,', 'The man''s desire to remain with Jesus ("that he might be with him" — the same language used for the call of the Twelve in Mark 3:14) is understandable and beautiful. He wants to stay close to his deliverer. But Jesus has a different assignment for him — one that only he can fulfill in his own community.', NULL),
  (39, 'Return to thine own house, and shew how great things God hath done unto thee. And he went his way, and published throughout the whole city how great things Jesus had done unto him.', 'Ὑπόστρεφε εἰς τὸν οἶκόν σου, καὶ διηγοῦ ὅσα σοι ἐποίησεν ὁ Θεός. καὶ ἀπῆλθεν καθ'' ὅλην τὴν πόλιν κηρύσσων ὅσα ἐποίησεν αὐτῷ ὁ Ἰησοῦς.', 'Hupostrephe eis ton oikon sou, kai diēgou hosa soi epoiēsen ho Theos. kai apēlthen kath'' holēn tēn polin kērussōn hosa epoiēsen autō ho Iēsous.', 'Jesus sends him back as a missionary to his own people — the first Gentile evangelist in Luke''s account. Instructively, Jesus says "tell what God hath done," and the man "published what Jesus had done" — a subtle Christological equation. He is the first person in Luke to be explicitly sent (apostellō-form commission) to proclaim rather than to follow. His home region becomes his mission field.', NULL),
  (40, 'And it came to pass, that, when Jesus was returned, the people gladly received him: for they were all waiting for him.', 'Ἐν δὲ τῷ ὑποστρέφειν τὸν Ἰησοῦν ἀπεδέξατο αὐτὸν ὁ ὄχλος· ἦσαν γὰρ πάντες προσδοκῶντες αὐτόν.', 'En de tō hupostrephein ton Iēsoun apedexato auton ho ochlos; ēsan gar pantes prosdokōntes auton.', 'The contrast with the Gadarene rejection is immediate: back in Galilee, the crowd "gladly received him" (apedexato — welcomed, accepted). "All waiting for him" (pantes prosdokōntes) — expectant anticipation. The Galilean crowd, primed by the reports of chapter 7, is ready to receive Jesus. Into this receptive crowd comes the urgent appeal of Jairus.', NULL),
  (41, 'And, behold, there came a man named Jairus, and he was a ruler of the synagogue: and he fell down at Jesus'' feet, and besought him that he would come into his house:', 'καὶ ἰδοὺ ἦλθεν ἀνὴρ ᾧ ὄνομα Ἰάειρος, καὶ αὐτὸς ἄρχων τῆς συναγωγῆς ὑπῆρχεν, καὶ πεσὼν παρὰ τοὺς πόδας τοῦ Ἰησοῦ παρεκάλει αὐτὸν εἰσελθεῖν εἰς τὸν οἶκον αὐτοῦ,', 'kai idou ēlthen anēr hō onoma Iaeiros, kai autos archōn tēs sunagōgēs hupērchen, kai pesōn para tous podas tou Iēsou parekalei auton eiselthein eis ton oikon autou,', 'Jairus (Hebrew: Ya''ir — "he enlightens") was a synagogue ruler (archōn tēs sunagōgēs) — a position of significant religious and social authority. His prostration before Jesus ("fell at his feet") was a radical act of humility. He was willing to risk his social standing and religious reputation in public desperation. The contrast with Simon the Pharisee (chapter 7) is sharp — here an official of the synagogue humbly seeks help.', NULL),
  (42, 'For he had one only daughter, about twelve years of age, and she lay a dying. But as he went the people thronged him.', 'ὅτι θυγάτηρ μονογενὴς ἦν αὐτῷ ὡς ἐτῶν δώδεκα καὶ αὕτη ἀπέθνῃσκεν. Ἐν δὲ τῷ ὑπάγειν αὐτὸν οἱ ὄχλοι συνέπνιγον αὐτόν.', 'hoti thugatēr monogenēs ēn autō hōs etōn dōdeka kai hautē apethnēsken. En de tō hupagein auton hoi ochloi sunepnigon auton.', '"Only daughter" (monogenēs) — the same word used for the widow''s son at Nain (7:12) and for Jesus in John 3:16. Age twelve and the twelve-year duration of the woman''s bleeding (v.43) form a literary bracket. "She lay a dying" (apethnēsken — imperfect: was in the process of dying). The urgency is acute. The crowd "thronged" (sunepnigon — the same word as "choked" the seed in v.7, creating a deliberate echo) — they pressed on him as he attempted to hasten to the dying girl.', NULL),
  (43, 'And a woman having an issue of blood twelve years, which had spent all her living upon physicians, neither could be healed of any,', 'καὶ γυνὴ οὖσα ἐν ῥύσει αἵματος ἀπὸ ἐτῶν δώδεκα, ἥτις ἰατροῖς προσαναλώσασα ὅλον τὸν βίον οὐκ ἴσχυσεν ἀπ'' οὐδενὸς θεραπευθῆναι,', 'kai gunē ousa en rhusei haimatos apo etōn dōdeka, hētis iatrois prosanalōsasa holon ton bion ouk ischuse ap'' oudenos therapeuthenai,', 'Luke the physician softens Mark''s critique of physicians (Mark 5:26) but retains the key facts: twelve years of suffering, all resources exhausted, no cure achieved by medical means. A woman with a chronic discharge was perpetually ritually unclean (Lev 15:25-27), excluded from worship and normal social contact. She had suffered social death alongside physical suffering. Her touching Jesus risked transmitting uncleanness — but instead the cleanness of Jesus flows the other way.', NULL),
  (44, 'Came behind him, and touched the border of his garment: and immediately her issue of blood stanched.', 'προσελθοῦσα ὄπισθεν ἥψατο τοῦ κρασπέδου τοῦ ἱματίου αὐτοῦ, καὶ παραχρῆμα ἔστη ἡ ῥύσις τοῦ αἵματος αὐτῆς.', 'proselthōusa opisthen hēpsato tou kraspedou tou himatiou autou, kai parachrēma estē hē rhusis tou haimatos autēs.', '"The border of his garment" (kraspedon — the tassel, fringe). Jewish men wore tassels on the corners of their garments (Num 15:38-40; Deut 22:12) as reminders of the commandments. The tassels may have represented the covenant promises. She touched the hem in faith, believing that even the edge of contact with Jesus was sufficient. "Immediately" (parachrēma) — instantaneous healing. The chronically unclean touched the holy and was made clean.', NULL),
  (45, 'And Jesus said, Who touched me? When all denied, Peter and they that were with him said, Master, the multitude throng thee and press thee, and sayest thou, Who touched me?', 'καὶ εἶπεν ὁ Ἰησοῦς, Τίς ὁ ἁψάμενός μου; ἀρνουμένων δὲ πάντων εἶπεν ὁ Πέτρος καὶ οἱ σὺν αὐτῷ, Ἐπιστάτα, οἱ ὄχλοι συνέχουσίν σε καὶ ἀποθλίβουσιν, καὶ λέγεις, Τίς ὁ ἁψάμενός μου;', 'kai eipen ho Iēsous, Tis ho hapsamenos mou? arnoumenōn de pantōn eipen ho Petros kai hoi sun autō, Epistata, hoi ochloi sunechousin se kai apothlibousin, kai legeis, Tis ho hapsamenos mou?', 'Jesus''s question is not ignorance but intentional drawing-out. Peter''s reply is practically reasonable but spiritually insufficient: the crowd is pressing, of course someone touched you. Jesus distinguishes between the press of the crowd and the touch of faith. Many brushed against Jesus that day; one person touched him. The difference was not physical contact but intentional faith — the outreaching hand of a believing heart.', NULL),
  (46, 'And Jesus said, Somebody hath touched me: for I perceive that virtue is gone out of me.', 'ὁ δὲ Ἰησοῦς εἶπεν, Ἥψατό μού τις· ἐγὼ γὰρ ἔγνων δύναμιν ἐξεληλυθυῖαν ἀπ'' ἐμοῦ.', 'ho de Iēsous eipen, Hēpsato mou tis; egō gar egnōn dunamin exelēluthuian ap'' emou.', '"Virtue is gone out of me" (dunamin exelēluthuian — power has gone out). Dunamin (power) is the same word used for the Spirit in 1:35 and 4:14. Healing power flows from Jesus as a real, personal force — not an impersonal energy but the grace of the Son of God directed toward a particular person in faith. The perfect participle "gone out" indicates a completed action with present effect: the healing was already accomplished.', NULL),
  (47, 'And when the woman saw that she was not hid, she came trembling, and falling down before him, she declared unto him before all the people for what cause she had touched him, and how she was healed immediately.', 'ἰδοῦσα δὲ ἡ γυνὴ ὅτι οὐκ ἔλαθεν, τρέμουσα ἦλθεν καὶ προσπεσοῦσα αὐτῷ, δι'' ἣν αἰτίαν ἥψατο αὐτοῦ ἀπήγγειλεν αὐτῷ ἐνώπιον παντὸς τοῦ λαοῦ, καὶ ὡς ἰάθη παραχρῆμα.', 'idousa de hē gunē hoti ouk elathen, tremousa ēlthen kai prospesōsa autō, di'' hēn aitian hēpsato autou apēngeilan autō enōpion pantos tou laou, kai hōs iathē parachrēma.', 'She came "trembling" (tremousa) — fearing rebuke for her unauthorized touch of a rabbi in her state of ritual impurity. Her falling before Jesus mirrors Jairus''s prostration (v.41). Her public declaration "before all the people" (enōpion pantos tou laou) — a testimony she was compelled to give publicly — is both her vindication and her witness. The shame she feared became the stage for her glorification.', NULL),
  (48, 'And he said unto her, Daughter, be of good comfort: thy faith hath made thee whole; go in peace.', 'ὁ δὲ εἶπεν αὐτῇ, Θύγατερ, ἡ πίστις σου σέσωκέν σε· πορεύου εἰς εἰρήνην.', 'ho de eipen autē, Thugater, hē pistis sou sesōken se; poreuou eis eirēnēn.', '"Daughter" (Thugater) — the only time in all four Gospels that Jesus calls any woman "daughter." The term of intimate family membership is bestowed on a woman who had been excluded from the community of Israel for twelve years. "Thy faith hath made thee whole" (sesōken — perfect: has saved and the salvation stands). "Go in peace" — the full shalom of restored relationship with God and community. This is the same dismissal given to the forgiven woman (7:50).', NULL),
  (49, 'While he yet spake, there cometh one from the ruler of the synagogue''s house, saying to him, Thy daughter is dead; trouble not the Master.', 'Ἔτι αὐτοῦ λαλοῦντος ἔρχεταί τις παρὰ τοῦ ἀρχισυναγώγου λέγων αὐτῷ ὅτι Τέθνηκεν ἡ θυγάτηρ σου· μηκέτι σκύλλε τὸν διδάσκαλον.', 'Eti autou lalountos erchetai tis para tou archisunagōgou legōn autō hoti Tethnēken hē thugatēr sou; mēketi skulle ton didaskalon.', '"While he yet spake" — the interruption arrives before the conversation with the healed woman is complete. The messenger''s report is devastating: "Thy daughter is dead." The imperative "trouble not the Master" reflects a rational but faithless conclusion: death is the limit of any healer''s power. The delay caused by the woman''s healing seemed to seal the girl''s fate. But what seems like a tragic complication is, in Luke''s narrative, a deliberate divine design.', NULL),
  (50, 'But when Jesus heard it, he answered him, saying, Fear not: believe only, and she shall be made whole.', 'ὁ δὲ Ἰησοῦς ἀκούσας ἀπεκρίθη αὐτῷ λέγων, Μὴ φοβοῦ, μόνον πίστευε, καὶ σωθήσεται.', 'ho de Iēsous akousas apekrithē autō legōn, Mē phobou, monon pisteue, kai sōthēsetai.', '"Fear not, believe only" (mē phobou, monon pisteue) — a double command. Fear and faith are mutually exclusive responses to the same news. The news says "too late"; faith says "not for Jesus." "She shall be made whole" (sōthēsetai — will be saved). The future passive of sōzō: salvation, not merely resuscitation. Jesus reframes the situation before arriving: the father must believe before seeing.', NULL),
  (51, 'And when he came into the house, he suffered no man to go in, save Peter, and James, and John, and the father and the mother of the maiden.', 'ἐλθὼν δὲ εἰς τὴν οἰκίαν οὐκ ἀφῆκεν εἰσελθεῖν τινα σὺν αὐτῷ εἰ μὴ Πέτρον καὶ Ἰωάννην καὶ Ἰάκωβον καὶ τὸν πατέρα τῆς παιδὸς καὶ τὴν μητέρα.', 'elthōn de eis tēn oikian ouk aphēken eiselthein tina sun autō ei mē Petron kai Iōannēn kai Iakōbon kai ton patera tēs paidos kai tēn mētera.', 'The inner circle — Peter, James, and John — will be the same witnesses at the Transfiguration (9:28). They are witnesses to Jesus''s most intimate and extraordinary acts. The parents are present as witnesses of identity: they knew this was their dead daughter, so they could authenticate the resurrection. The limitation of witnesses preserves solemnity and prevents sensationalism.', NULL),
  (52, 'And all wept, and bewailed her: but he said, Weep not; she is not dead, but sleepeth.', 'ἔκλαιον δὲ πάντες καὶ ἐκόπτοντο αὐτήν· ὁ δὲ εἶπεν, Μὴ κλαίετε· οὐκ ἀπέθανεν ἀλλὰ καθεύδει.', 'eklaion de pantes kai ekoptonto autēn; ho de eipen, Mē klaiete; ouk apethanen alla katheudei.', '"All wept and bewailed her" — professional mourners (a Jewish custom) and genuine family grief together filled the house. "She is not dead, but sleepeth" (katheudei) — Jesus uses the metaphor of sleep for death (also 1 Cor 15:6; 1 Thess 4:13-16; John 11:11-14). The sleep metaphor is not denial of death but a redefinition from the perspective of one who will wake her. Death is reversible by Jesus; it is, from his vantage point, merely interrupted sleep.', NULL),
  (53, 'And they laughed him to scorn, knowing that she was dead.', 'καὶ κατεγέλων αὐτοῦ, εἰδότες ὅτι ἀπέθανεν.', 'kai kategelōn autou, eidotes hoti apethanen.', '"They laughed him to scorn" (kategelōn — mocked, derided). Their laughter is the laughter of worldly certainty that regards death as absolute and final. They knew she was dead (eidotes — knowing with certainty). Their certainty becomes the backdrop against which the miracle is displayed. The mocking crowd is excluded from witnessing what only faith and humility will see.', NULL),
  (54, 'And he put them all out, and took her by the hand, and called, saying, Maid, arise.', 'αὐτὸς δὲ ἐκβαλὼν ἔξω πάντας καὶ κρατήσας τῆς χειρὸς αὐτῆς ἐφώνησεν λέγων, Ἡ παῖς, ἐγείρου.', 'autos de ekbalōn exō pantas kai kratēsas tēs cheiros autēs ephōnēsen legōn, Hē pais, egeirou.', '"He put them all out" — cleared the house of those whose unbelief would contaminate the atmosphere. Then he "took her by the hand" — touching a corpse, which was the supreme source of ritual defilement (Num 19:11). As with the leper and the funeral bier, Jesus touches what is unclean without becoming defiled; instead, his touch conveys life. "Maid, arise" (Hē pais, egeirou) — a simple, direct, personal command.', NULL),
  (55, 'And her spirit came again, and she arose straightway: and he commanded to give her meat.', 'καὶ ἐπέστρεψεν τὸ πνεῦμα αὐτῆς, καὶ ἀνέστη παραχρῆμα· καὶ διέταξεν αὐτῇ δοθῆναι φαγεῖν.', 'kai epestrepsen to pneuma autēs, kai anestē parachrēma; kai dietaxen autē dothēnai phagein.', '"Her spirit came again" (epestrepsen to pneuma autēs) — the spirit returned to the body. Luke the physician notes the physical sign of genuine bodily resurrection: she needs food. Her hunger is proof of life restored, not a vision or illusion. The command to feed her shows Jesus''s practical care for the whole person — not just dramatic miracle but ongoing nurture.', NULL),
  (56, 'And her parents were astonished: but he charged them that they should tell no man what was done.', 'καὶ ἐξέστησαν οἱ γονεῖς αὐτῆς· ὁ δὲ παρήγγειλεν αὐτοῖς μηδενὶ εἰπεῖν τὸ γεγονός.', 'kai exestēsan hoi goneis autēs; ho de parēngeilen autois mēdeni eipein to gegonos.', '"Astonished" (exestēsan — beside themselves, ecstatic with wonder). The command to silence is paradoxical given the presence of mourners outside, but it reflects Jesus''s consistent pattern of limiting sensationalism around resurrection miracles (cf. 9:21). The focus of the chapter ends on the parents'' wonder — the appropriate response to a God who visits his people, calms their storms, delivers their captives, heals their sick, and raises their dead.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 8;
